-- Centralized scam blocklist shared across all installs.
-- Replaces the previously bundled assets/data/known_risks.json file.
--
-- Lookups: app fetches all rows on startup (cached locally for offline use).
-- Native CallScreeningService still reads its blocklist from a SharedPreferences
-- snapshot synced from this table.

create table if not exists public.known_risks (
  id uuid primary key default gen_random_uuid(),
  type text not null check (type in ('phone', 'bankAccount', 'url')),
  value text not null,
  normalized_value text not null,
  risk_level text not null check (risk_level in ('safe', 'suspicious', 'scam')),
  score int not null check (score between 0 and 100),
  summary text default '',
  reasons jsonb not null default '[]'::jsonb,
  psychological jsonb not null default '{}'::jsonb,
  linguistic_signals jsonb not null default '[]'::jsonb,
  cyber_signals jsonb not null default '[]'::jsonb,
  social_tactics jsonb not null default '[]'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (type, normalized_value)
);

create index if not exists known_risks_normalized_idx on public.known_risks (normalized_value);
create index if not exists known_risks_type_level_idx on public.known_risks (type, risk_level);

-- Updated-at trigger so client cache can detect changes.
create or replace function public.known_risks_touch_updated_at()
returns trigger language plpgsql as $$
begin
  new.updated_at := now();
  return new;
end $$;

drop trigger if exists known_risks_touch on public.known_risks;
create trigger known_risks_touch before update on public.known_risks
  for each row execute function public.known_risks_touch_updated_at();

-- Demo policy: anon can read everything, can also insert/update so the app
-- can submit community reports. Tighten to authenticated-only before go-prod.
alter table public.known_risks enable row level security;

drop policy if exists "anon read known_risks" on public.known_risks;
create policy "anon read known_risks" on public.known_risks
  for select to anon using (true);

drop policy if exists "anon insert known_risks" on public.known_risks;
create policy "anon insert known_risks" on public.known_risks
  for insert to anon with check (true);

drop policy if exists "anon update known_risks" on public.known_risks;
create policy "anon update known_risks" on public.known_risks
  for update to anon using (true) with check (true);

on conflict (type, normalized_value) do update set
  value = excluded.value,
  risk_level = excluded.risk_level,
  score = excluded.score,
  summary = excluded.summary,
  reasons = excluded.reasons,
  psychological = excluded.psychological,
  linguistic_signals = excluded.linguistic_signals,
  cyber_signals = excluded.cyber_signals,
  social_tactics = excluded.social_tactics;
