insert into public.known_risks
  (type, value, normalized_value, risk_level, score, summary, reasons, psychological, linguistic_signals, cyber_signals, social_tactics)
values
  ('phone', '0888888888', '0888888888', 'scam', 95, 'Số nằm trong danh sách lừa đảo đã được báo cáo nhiều lần.', '["Đã được báo cáo lừa đảo bởi nhiều nạn nhân.", "Mạo danh cơ quan công an để yêu cầu chuyển tiền.", "Sử dụng kịch bản đe doạ phong toả tài khoản."]'::jsonb, '{"urgency": 90, "fear": 95, "authority": 90, "greed": 10}'::jsonb, '["Sử dụng cụm từ kịch bản: ''tài khoản của bạn liên quan đường dây ma tuý''.", "Hối thúc liên tục bằng các từ khoá: ''ngay lập tức'', ''trong 5 phút''.", "Xưng hô không nhất quán (anh/chị/đồng chí) — dấu hiệu đọc kịch bản."]'::jsonb, '["Số nằm trong dải đầu thường được gắn cho các vụ giả danh cơ quan công an.", "Có thể giả lập caller ID — đối chiếu với tổng đài chính thức 113."]'::jsonb, '["Authority: giả danh công an / viện kiểm sát.", "Scarcity: tạo deadline ngắn để nạn nhân không kịp suy nghĩ.", "Commitment: ép cung cấp thông tin nhỏ trước rồi leo thang."]'::jsonb),
  ('phone', '0911222333', '0911222333', 'scam', 88, 'Số giả danh ngân hàng yêu cầu cập nhật thông tin tài khoản.', '["Mạo danh nhân viên ngân hàng.", "Yêu cầu cung cấp OTP, mã PIN hoặc mật khẩu.", "Hối thúc thực hiện giao dịch trong vài phút."]'::jsonb, '{"urgency": 85, "fear": 70, "authority": 80, "greed": 20}'::jsonb, '["Dùng từ chuyên ngành ngân hàng sai ngữ cảnh (''xác minh OTP cấp 2'').", "Câu mở đầu đặc trưng: ''Đây là tổng đài ABC Bank, gọi xác minh giao dịch''."]'::jsonb, '["Ngân hàng KHÔNG bao giờ hỏi OTP/PIN/mật khẩu qua điện thoại.", "Tổng đài chính thức của các ngân hàng VN bắt đầu bằng 1900 hoặc 1800."]'::jsonb, '["Authority: giả danh nhân viên ngân hàng.", "Urgency: ''tài khoản bị khoá trong 10 phút nếu không xác minh''."]'::jsonb),
  ('phone', '0369218921', '0369218921', 'scam', 93, 'Số bị tố cáo nhiều lần là lừa đảo qua điện thoại.', '["Có nhiều nạn nhân báo cáo bị lừa chuyển tiền.", "Tự xưng nhân viên giao hàng / shipper để dụ click link giả.", "Yêu cầu xác minh đơn hàng qua đường link lạ."]'::jsonb, '{"urgency": 85, "fear": 50, "authority": 70, "greed": 60}'::jsonb, '["Câu mẫu: ''Đơn hàng của bạn không giao được, vui lòng xác minh tại link…''.", "Sử dụng tên thương hiệu giao hàng (GHTK / SPX / J&T) để tăng độ tin cậy."]'::jsonb, '["Link xác minh không thuộc tên miền chính thức của hãng giao hàng.", "Trang đích thường lừa người dùng nhập OTP / số thẻ ngân hàng."]'::jsonb, '["Liking: tự xưng shipper, gọi tên thân thiện để hạ rào cản nghi ngờ.", "Commitment: xác nhận đơn hàng nhỏ trước rồi leo thang lên thanh toán."]'::jsonb),
  ('phone', '0388123456', '0388123456', 'suspicious', 55, 'Có một vài báo cáo nghi ngờ liên quan đến chào mời đầu tư.', '["Một số người dùng phản ánh nhận được lời mời đầu tư lãi cao bất thường.", "Chưa đủ bằng chứng để khẳng định lừa đảo nhưng cần cẩn trọng."]'::jsonb, '{"urgency": 40, "fear": 10, "authority": 30, "greed": 75}'::jsonb, '["Cụm từ marketing: ''lãi 30%/tháng'', ''bảo toàn vốn 100%'' — không có thật."]'::jsonb, '["Thường mời thêm Telegram / Zalo group, ngoài nền tảng có kiểm soát."]'::jsonb, '["Greed: hứa lợi nhuận cao bất thường.", "Social Proof: gửi screenshot ''người khác đã rút tiền thành công''."]'::jsonb),
  ('phone', '0838383838', '0838383838', 'scam', 92, 'Giả danh cán bộ Bộ Công an, đe doạ liên quan đến án ma tuý.', '["Tự xưng cán bộ điều tra Bộ Công an.", "Đọc đúng họ tên / CCCD nạn nhân để tăng độ tin cậy.", "Yêu cầu chuyển tiền vào ''tài khoản giám định'' để chứng minh trong sạch."]'::jsonb, '{"urgency": 92, "fear": 95, "authority": 95, "greed": 5}'::jsonb, '["Cụm từ: ''lệnh bắt khẩn cấp'', ''phong toả tài sản''.", "Doạ truy tố hình sự nếu không hợp tác."]'::jsonb, '["Công an thật KHÔNG làm việc qua điện thoại — đến trụ sở trực tiếp."]'::jsonb, '["Authority: giả danh công an cấp cao.", "Fear: đe doạ tù tội."]'::jsonb),
